import{_ as s,o as n,c as e,a2 as r}from"./chunks/framework.y1bVONfd.js";const u=JSON.parse('{"title":"架构概览","description":"WebRouter 架构设计","frontmatter":{"title":"架构概览","description":"WebRouter 架构设计"},"headers":[],"relativePath":"zh/guide/architecture.md","filePath":"zh/guide/architecture.md"}'),t={name:"zh/guide/architecture.md"};function l(o,a,i,p,c,d){return n(),e("div",null,[...a[0]||(a[0]=[r(`<h1 id="架构概览" tabindex="-1">架构概览 <a class="header-anchor" href="#架构概览" aria-label="Permalink to &quot;架构概览&quot;">​</a></h1><h2 id="组件架构" tabindex="-1">组件架构 <a class="header-anchor" href="#组件架构" aria-label="Permalink to &quot;组件架构&quot;">​</a></h2><p>WebRouter 由两个主要组件构成：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────┐     HTTP      ┌─────────────────┐</span></span>
<span class="line"><span>│  浏览器/CLI  │ ───────────→ │    WebRouter     │</span></span>
<span class="line"><span>│             │ ←──────────── │    (Flask)       │</span></span>
<span class="line"><span>└─────────────┘               │    :5050         │</span></span>
<span class="line"><span>                              └──────┬──────────┘</span></span>
<span class="line"><span>                                     │</span></span>
<span class="line"><span>                              ┌──────▼──────┐</span></span>
<span class="line"><span>                              │  wr-proxy    │</span></span>
<span class="line"><span>                              │  (Go) :5051  │</span></span>
<span class="line"><span>                              └──────┬──────┘</span></span>
<span class="line"><span>                                     │</span></span>
<span class="line"><span>                     ┌───────────────┼───────────────┐</span></span>
<span class="line"><span>                     │               │               │</span></span>
<span class="line"><span>              ┌──────▼──────┐ ┌──────▼──────┐ ┌──────▼──────┐</span></span>
<span class="line"><span>              │   direct    │ │  aggregate  │ │   custom    │</span></span>
<span class="line"><span>              │  (官方直连)  │ │  (聚合平台)  │ │ (自定义网关) │</span></span>
<span class="line"><span>              └─────────────┘ └─────────────┘ └─────────────┘</span></span></code></pre></div><h2 id="组件说明" tabindex="-1">组件说明 <a class="header-anchor" href="#组件说明" aria-label="Permalink to &quot;组件说明&quot;">​</a></h2><h3 id="webrouter-flask-后端" tabindex="-1">WebRouter（Flask 后端） <a class="header-anchor" href="#webrouter-flask-后端" aria-label="Permalink to &quot;WebRouter（Flask 后端）&quot;">​</a></h3><p>管理面板和 REST API 服务：</p><ul><li><strong>端口：</strong> 5050</li><li><strong>语言：</strong> Python Flask</li><li><strong>职责：</strong> 数据源管理、令牌管理、健康监控、计费、团队管理、系统设置</li><li><strong>数据库：</strong> SQLite（默认）或 MySQL/PostgreSQL</li><li><strong>调度器：</strong> APScheduler，定时健康检测和告警评估</li></ul><h3 id="wr-proxy-go-代理网关" tabindex="-1">wr-proxy（Go 代理网关） <a class="header-anchor" href="#wr-proxy-go-代理网关" aria-label="Permalink to &quot;wr-proxy（Go 代理网关）&quot;">​</a></h3><p>高性能请求代理：</p><ul><li><strong>端口：</strong> 5051</li><li><strong>语言：</strong> Go 1.22</li><li><strong>职责：</strong> 请求转发、智能路由、退避重试、隐私脱敏、流式传输、成本计量</li></ul><h2 id="数据流" tabindex="-1">数据流 <a class="header-anchor" href="#数据流" aria-label="Permalink to &quot;数据流&quot;">​</a></h2><ol><li><strong>客户端发送请求</strong> 到 wr-proxy（携带 WebRouter API Key）</li><li><strong>wr-proxy 认证</strong> Token 并基于模型或 <code>auto</code> 路由选择最优 Provider</li><li><strong>脱敏引擎</strong> 从请求体中剥离 PII</li><li><strong>转发</strong> 请求到上游 Provider</li><li><strong>计量</strong> Token 消耗和成本</li><li><strong>返回</strong> 响应给客户端（如有需要则还原脱敏数据）</li></ol>`,13)])])}const g=s(t,[["render",l]]);export{u as __pageData,g as default};
